test("SDK-shaped receipt classification has explicit terminal precedence",()=>{const cases=[
 [receipt("FINALIZED","AGREE","FINISHED_WITH_RETURN"),"finalized success",true],
 [receipt("FINALIZED","AGREE","FINISHED_WITH_ERROR"),"execution failure",true],
 [receipt("ACCEPTED","AGREE","FINISHED_WITH_RETURN"),"confirmation/accepted",false],[receipt("ACCEPTED","AGREE","FINISHED_WITH_ERROR"),"confirmation/accepted",false],
 [receipt("READY_TO_FINALIZE","AGREE","FINISHED_WITH_RETURN"),"ready to finalize",false],
 [receipt("CANCELED"),"canceled",true],[receipt("VALIDATORS_TIMEOUT"),"timeout",true],[receipt("LEADER_TIMEOUT"),"timeout",true],
 [receipt("UNDETERMINED","TIMEOUT"),"timeout",true],[receipt("UNDETERMINED","NO_MAJORITY"),"no majority",true],[receipt("UNDETERMINED","DISAGREE"),"disagreement/failure",true],
 [receipt("UNDETERMINED","MAJORITY_DISAGREE"),"disagreement/failure",true],[receipt("UNDETERMINED","DETERMINISTIC_VIOLATION"),"disagreement/failure",true]
 ];for(const [input,phase,terminal] of cases){const result=classifyReceipt(input);assert.equal(result.currentPhase,phase);assert.equal(result.terminal,terminal)}});
