 const baseTransaction={statusName:"FINALIZED",txExecutionResultName:"FINISHED_WITH_RETURN",txDataDecoded:{type:"deploy",contractAddress:deployedAddress}};
 async function rejected({transaction=baseTransaction,remoteSource=source,localSchema=validSchema,deployedSchema=validSchema,chainId=4221,codeError=null,compileError=null,schemaError=null}={}){let codeCalls=0,schemaCalls=0,transactionCalls=0;const client={chain:{id:4221},getChainId:async()=>chainId,getContractSchemaForCode:async()=>{if(compileError)throw compileError;return localSchema},waitForTransactionReceipt:async()=>({status_name:"FINALIZED"}),getTransaction:async()=>{transactionCalls++;return transaction},getContractCode:async()=>{codeCalls++;if(codeError)throw codeError;return remoteSource},getContractSchema:async()=>{schemaCalls++;if(schemaError)throw schemaError;return deployedSchema}};let expectedSchema=localSchema;if(!compileError){try{expectedSchema=await compileExpectedSchema(client,source)}catch{expectedSchema=localSchema}}await assert.rejects(()=>verifyFinalizedDeployment({client,hash,source,expectedSchema}));return{codeCalls,schemaCalls,transactionCalls}}
