test("schema comparison rejects the complete independent mutation matrix",()=>{
 const mutationCases=[
  ["changed method name",schema=>{schema.methods.renamed=schema.methods.alpha;delete schema.methods.alpha}],
  ["missing method",schema=>{delete schema.methods.beta}],
  ["extra method",schema=>{schema.methods.extra=structuredClone(schema.methods.beta)}],
  ["positional name",schema=>{schema.methods.alpha.params[0][0]="renamed"}],
  ["positional type",schema=>{schema.methods.alpha.params[0][1]="bytes"}],
  ["positional order",schema=>{schema.methods.alpha.params.reverse()}],
  ["keyword name",schema=>{schema.methods.alpha.kwparams.renamed=schema.methods.alpha.kwparams.meta;delete schema.methods.alpha.kwparams.meta}],
  ["keyword type",schema=>{schema.methods.alpha.kwparams.meta={field:"bytes"}}],
  ["return type",schema=>{schema.methods.alpha.ret=["string","bytes"]}],
  ["readonly",schema=>{schema.methods.alpha.readonly=true}],
  ["payable",schema=>{schema.methods.alpha.payable=false}],
  ["remove optional payable",schema=>{delete schema.methods.alpha.payable}],
  ["add optional payable",schema=>{schema.methods.beta.payable=false}],
  ["constructor positional",schema=>{schema.ctor.params[0][0]="renamed"}],
  ["constructor keyword",schema=>{schema.ctor.kwparams.options={$dict:"bytes"}}],
  ["or choice",schema=>{schema.methods.alpha.kwparams.choice.$or[1]="bytes"}],
  ["dict value",schema=>{schema.methods.alpha.kwparams.lookup.$dict="string"}],
  ["record field",schema=>{schema.methods.alpha.kwparams.meta={other:"string"}}],
  ["rep element",schema=>{schema.methods.alpha.params[1][1][0].$rep="string"}],
  ["array order",schema=>{schema.methods.alpha.ret.reverse()}],
 ];
 for(const [name,mutate] of mutationCases){const changed=structuredClone(structuredComparisonSchema);mutate(changed);assert.equal(validateContractSchema(changed),true,name);assert.equal(contractSchemasEqual(structuredComparisonSchema,changed),false,name)}
 const reordered={methods:{beta:{readonly:true,ret:"null",kwparams:{},params:[]},alpha:{payable:true,readonly:false,ret:["string","int"],kwparams:{empty:{},lookup:{$dict:"int"},choice:{$or:["string","null"]},meta:{field:"string"}},params:[["value","string"],["items",[{$rep:"int"}]]]}},ctor:{kwparams:{options:{$dict:"string"}},params:[["seed",{$or:["string","null"]}]]}};assert.equal(contractSchemasEqual(structuredComparisonSchema,reordered),true);
 const shared={$or:["string","null"]},sharedSchema=structuredClone(structuredComparisonSchema);sharedSchema.ctor.params[0][1]=shared;sharedSchema.methods.alpha.kwparams.choice=shared;assert.equal(validateContractSchema(sharedSchema),true);assert.equal(contractSchemasEqual(sharedSchema,structuredClone(sharedSchema)),true);
});
