test("deployment and wrapper cookie redaction consumes complete logical header values",()=>{
 const cases=[
  {message:"Cookie: first=secretone; second=secrettwo",forbidden:/secretone|secrettwo|first=|second=/i},
  {message:"Cookie: first=secretone; second=secrettwo; third=secretthree",forbidden:/secretone|secrettwo|secretthree|first=|second=|third=/i},
  {message:"Cookie=first=secretone; second=secrettwo",forbidden:/secretone|secrettwo|first=|second=/i},
  {message:"Set-Cookie: auth=supersecret; Secure; HttpOnly; SameSite=Lax",forbidden:/auth=|supersecret|Secure|HttpOnly|SameSite=Lax/i},
  {message:"Set-Cookie=session=supersecret; Path=/; Max-Age=3600",forbidden:/session=|supersecret|Path=|Max-Age|3600/i},
  {message:'"Cookie": "first=secretone; second=secrettwo"',forbidden:/secretone|secrettwo|first=|second=/i},
  {message:"'Cookie': 'first=secretone; second=secrettwo'",forbidden:/secretone|secrettwo|first=|second=/i},
  {message:'"Set-Cookie": "auth=supersecret; Secure; HttpOnly"',forbidden:/auth=|supersecret|Secure|HttpOnly/i},
  {message:"Cookie: first=secretone; second=secrettwo\nCookie: third=secretthree",forbidden:/secretone|secrettwo|secretthree|first=|second=|third=/i},
  {message:"Set-Cookie: first=secretone; Path=/\rSet-Cookie: second=secrettwo; HttpOnly",forbidden:/secretone|secrettwo|first=|second=|Path=|HttpOnly/i},
  {message:"Cookie:\tfirst=secretone; second=secrettwo\r\nAuthorization: Bearer anothersecret",forbidden:/secretone|secrettwo|anothersecret|first=|second=/i},
  {message:'{"Cookie":"first=secretone; second=secrettwo"}',forbidden:/secretone|secrettwo|first=|second=/i},
  {message:'{"Set-Cookie":"auth=supersecret; Secure"}',forbidden:/auth=|supersecret|Secure/i},
  {message:"Set-Cookie: expires=Wed, 21 Oct 2026 07:28:00 GMT; auth=supersecret",forbidden:/expires=|Wed|2026|GMT|auth=|supersecret/i},
 ];
 for(const {message,forbidden} of cases){for(const output of [formatCliError({message}),wrapperErrorDetails({message}).message]){assert.match(output,/\[REDACTED_SECRET\]/,message);assert.doesNotMatch(output,forbidden,message)}}
 const boundary="Cookie: first="+"x".repeat(4050)+"; second=secrettwo";for(const output of [formatCliError({message:boundary}),wrapperErrorDetails({message:boundary}).message]){assert.match(output,/\[REDACTED_SECRET\]/);assert.doesNotMatch(output,/first=|second=|secrettwo|x{8}/i)}
 for(const message of ["The browser cookie could not be read.","Cookie handling is disabled.","This request contains no cookie header.","The Set-Cookie parser is unavailable.","Cookie support is required."]){assert.equal(formatCliError({message}),message);assert.equal(wrapperErrorDetails({message}).message,message)}
});
